class Theater {
    - location : String
    - name : String
}
abstract class Play {
    - name : String
    - timeOfDay : TimeOfDay
}
class Musical {
}
class Opera {
}
class Author {
    - name : String
}
class Participant {
    - name : String
}
class Session {
    - scheduledDate : Date
